begin;
update assessments set subtitle='A Church Planting Readiness Assessment',category='ministry',scale_min=1,scale_max=5,estimated_minutes=18,questions_per_page=15,sensitivity='standard',is_published=false where slug='church-planter';
delete from items where assessment_id=(select id from assessments where slug='church-planter');
with a as (select id from assessments where slug='church-planter') insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type) select a.id,v.ord,v.txt,v.dom,v.sc,v.rev,v.it::item_type from a,(values (1,'I have started something from nothing and seen it grow.','Visioning Capacity',true,false,'paraphrase_pair'),(2,'I have launched a ministry, group, or venture that did not exist before I began it.','Visioning Capacity',true,false,'paraphrase_pair'),(3,'I can describe a future that doesn''t exist yet in a way that makes others want to be part of it.','Visioning Capacity',true,false,'standard'),(4,'People have joined an effort mainly because of a picture of the future I gave them.','Visioning Capacity',true,false,'standard'),(5,'I am better at maintaining what already exists than starting something new.','Visioning Capacity',true,true,'reverse'),(6,'I keep working hard toward a goal even when no one is checking on me.','Intrinsically Motivated',true,false,'paraphrase_pair'),(7,'I stay driven on a project even with no supervision or accountability at all.','Intrinsically Motivated',true,false,'paraphrase_pair'),(8,'I have pushed through long, hard seasons of work because the goal mattered to me.','Intrinsically Motivated',true,false,'standard'),(9,'I hold my own work to a higher standard than others require of me.','Intrinsically Motivated',true,false,'standard'),(10,'I tend to lose steam on goals unless someone is holding me accountable.','Intrinsically Motivated',true,true,'reverse'),(11,'People I have led took real ownership, not just followed my instructions.','Creates Ownership of Ministry',true,false,'paraphrase_pair'),(12,'Those I lead end up owning the work themselves rather than just doing what I say.','Creates Ownership of Ministry',true,false,'paraphrase_pair'),(13,'I have handed off real responsibility and watched others carry it well.','Creates Ownership of Ministry',true,false,'standard'),(14,'I have trained someone who went on to lead others.','Creates Ownership of Ministry',true,false,'standard'),(15,'I find it hard to let go of control of things I care about.','Creates Ownership of Ministry',true,true,'reverse'),(16,'I regularly build genuine friendships with people who don''t go to church.','Reaches the Unchurched',true,false,'paraphrase_pair'),(17,'Several of my real friendships are with people who are far from God.','Reaches the Unchurched',true,false,'paraphrase_pair'),(18,'People far from God seem comfortable around me.','Reaches the Unchurched',true,false,'standard'),(19,'I have personally helped someone outside the church move toward faith in Christ.','Reaches the Unchurched',true,false,'standard'),(20,'Almost everyone I spend time with is already a churchgoer.','Reaches the Unchurched',true,true,'reverse'),(21,'My spouse and I are united in the call to plant.','Spousal Cooperation',true,false,'paraphrase_pair'),(22,'My spouse is as committed to planting as I am.','Spousal Cooperation',true,false,'paraphrase_pair'),(23,'We have talked honestly about what planting will cost our family, and we are agreed.','Spousal Cooperation',true,false,'standard'),(24,'Our marriage is healthy enough to carry the strain of a plant.','Spousal Cooperation',true,false,'standard'),(25,'My spouse has real hesitations about planting that we have not resolved.','Spousal Cooperation',true,true,'reverse'),(26,'People find me easy to approach and relate to.','Effectively Builds Relationships',true,false,'paraphrase_pair'),(27,'Others generally find me easy to get along with.','Effectively Builds Relationships',true,false,'paraphrase_pair'),(28,'I make and keep friendships across different kinds of people.','Effectively Builds Relationships',true,false,'standard'),(29,'People tend to open up to me fairly quickly.','Effectively Builds Relationships',true,false,'standard'),(30,'I find it difficult to build close relationships.','Effectively Builds Relationships',true,true,'reverse'),(31,'I actively want the ministries I lead to grow, not just stay steady.','Committed to Church Growth',true,false,'paraphrase_pair'),(32,'I am driven to see the ministries I lead reach more people, not just hold steady.','Committed to Church Growth',true,false,'paraphrase_pair'),(33,'I have changed my methods in order to reach more people.','Committed to Church Growth',true,false,'standard'),(34,'I keep learning new approaches to ministry.','Committed to Church Growth',true,false,'standard'),(35,'I am content when a ministry stays about the same size year to year.','Committed to Church Growth',true,true,'reverse'),(36,'I have shaped ministry around the actual needs of a specific community.','Responsive to the Community',true,false,'paraphrase_pair'),(37,'I have built ministry around a community''s real, specific needs.','Responsive to the Community',true,false,'paraphrase_pair'),(38,'I pay attention to what a community needs before deciding what to offer.','Responsive to the Community',true,false,'standard'),(39,'I have met a concrete community need as a way into relationship.','Responsive to the Community',true,false,'standard'),(40,'I tend to run the same ministry approach regardless of the community.','Responsive to the Community',true,true,'reverse'),(41,'I help people discover what they are good at and place them there.','Utilizes the Giftedness of Others',true,false,'paraphrase_pair'),(42,'I put people in roles that match their strengths.','Utilizes the Giftedness of Others',true,false,'paraphrase_pair'),(43,'I have built a team by matching people to their gifts.','Utilizes the Giftedness of Others',true,false,'standard'),(44,'I would rather equip others than try to do it all myself.','Utilizes the Giftedness of Others',true,false,'standard'),(45,'When I need something done well, I usually just do it myself.','Utilizes the Giftedness of Others',true,true,'reverse'),(46,'I adjust my plans when the situation changes, without losing the goal.','Flexible and Adaptable',true,false,'paraphrase_pair'),(47,'When circumstances shift, I adapt my plan while keeping the mission.','Flexible and Adaptable',true,false,'paraphrase_pair'),(48,'I stay effective when things don''t go as planned.','Flexible and Adaptable',true,false,'standard'),(49,'I can hold my plan loosely while holding the mission firmly.','Flexible and Adaptable',true,false,'standard'),(50,'I get thrown off when things don''t go the way I planned.','Flexible and Adaptable',true,true,'reverse'),(51,'I have started small groups that became close and lasting.','Builds Group Cohesiveness',true,false,'paraphrase_pair'),(52,'Groups I have started tend to become tight-knit and stay together.','Builds Group Cohesiveness',true,false,'paraphrase_pair'),(53,'People I bring together tend to bond.','Builds Group Cohesiveness',true,false,'standard'),(54,'I know how to move a group from strangers to a team.','Builds Group Cohesiveness',true,false,'standard'),(55,'Groups I lead tend to stay loose and disconnected.','Builds Group Cohesiveness',true,true,'reverse'),(56,'I have recovered and kept going after a real ministry setback.','Resilience',true,false,'paraphrase_pair'),(57,'After a real failure or setback, I bounce back and keep moving.','Resilience',true,false,'paraphrase_pair'),(58,'Criticism and failure don''t keep me down for long.','Resilience',true,false,'standard'),(59,'I have stayed steady through a discouraging stretch.','Resilience',true,false,'standard'),(60,'Setbacks and criticism tend to keep me down for a long time.','Resilience',true,true,'reverse'),(61,'I have stepped out on something only God could accomplish and trusted Him for it.','Exercises Faith',true,false,'paraphrase_pair'),(62,'I have taken a real step of faith that depended on God coming through.','Exercises Faith',true,false,'paraphrase_pair'),(63,'My walk with God is the real engine behind my ministry.','Exercises Faith',true,false,'standard'),(64,'I have believed God for provision or breakthrough and seen Him come through.','Exercises Faith',true,false,'standard'),(65,'My ministry runs mostly on my own ability rather than active faith.','Exercises Faith',true,true,'reverse'),(66,'I have never exaggerated my role in something that went well.','Candor',false,false,'candor'),(67,'I always follow through on every single commitment I make.','Candor',false,false,'candor'),(68,'I have never avoided a difficult conversation I should have had.','Candor',false,false,'candor'),(69,'I never feel discouraged in ministry.','Candor',false,false,'candor'),(70,'I have never let a teammate down.','Candor',false,false,'candor'),(71,'I have never spoken about someone in a way I later regretted.','Candor',false,false,'candor'),(72,'To show you are reading carefully, please select Disagree for this item.','Attention',false,false,'candor'),(73,'I have succeeded at everything I have ever attempted.','Attention',false,false,'candor')) as v(ord,txt,dom,sc,rev,it);
